import { setIGNHeaderAndFooter } from "../../../src/lib/global-navigation/ign";

afterEach(() => {
  document.head.innerHTML = "";
  document.body.innerHTML = "";
});

test("It inserts a header container", () => {
  setIGNHeaderAndFooter({ headerId: "ign-header" });
  let header = document.getElementById("ign-header");
  expect(header.id).toBe("ign-header");
  expect(header.className).toBe("ign-header");
  expect(header.getAttribute("role")).toBe("navigation");
});

test("It sets up the project configuration for the IGN with good config ", () => {
  const config = {
    headerId: "ign-header",
    brandCode: "maeu",
    settings: {
      version: "stable",
      disableOpacityChange: true
    },
    assetsLocationMap: {
      test: "test"
    }
  };
  setIGNHeaderAndFooter(config);
  expect(window.projectServices.brand).toBe(config.brandCode);
  expect(window.projectServices.version).toBe(config.settings.version);
  expect(window.projectServices.ASSETS_ENV).toBe("test");
  expect(window.projectServices.disableOpacityChange).toBe(true);

  let loaderElem = document.getElementsByTagName("script")[0];
  expect(loaderElem.src).toBe("https://test.maerskline.com/integrated-global-nav/2/loader.js");
});

test("It sets up the project configuration for the IGN with bad config ", () => {
  const config = {
    headerId: "ign-header",
    brandCode: "svitz",
    settings: {
      version: true,
      disableOpacityChange: "true"
    },
    assetsLocationMap: {
      test: "bob"
    }
  };
  setIGNHeaderAndFooter(config);
  expect(window.projectServices.brand).toBe(config.brandCode);
  expect(window.projectServices.version).toBe(undefined);
  expect(window.projectServices.ASSETS_ENV).toBe("test");
  expect(window.projectServices.disableOpacityChange).toBe(undefined);

  let loaderElem = document.getElementsByTagName("script")[0];
  expect(loaderElem.src).toBe("https://bob.maerskline.com/integrated-global-nav/2/loader.js");
});
